    fn tokenToSymbol(self: *BaseParser, token: Token) u16 {
        return switch (token.cat) {
            .@"eof" => 1,
            .@"ident" => self.identToSymbol(token),
            .@"newline" => 66,
            .@"drop_stmt" => 71,
            .@"string_sq" => 76,
            .@"string_dq" => 77,
            .@"indent" => 82,
            .@"outdent" => 83,
            .@"kwarg_name" => 93,
            .@"suffix_q" => 102,
            .@"suffix_bang" => 103,
            .@"read_pfx" => 104,
            .@"write_pfx" => 105,
            .@"integer" => 108,
            .@"bar_capture" => 114,
            .@"share_pfx" => 119,
            .@"dot_lit" => 123,
            .@"ternary_if" => 130,
            .@"post_if" => 133,
            .@"minus_prefix" => 144,
            .@"move_pfx" => 147,
            .@"clone_pfx" => 148,
            .@"pin_pfx" => 149,
            .@"raw_pfx" => 150,
            .@"real" => 156,
            .@"true" => 157,
            .@"false" => 158,
            .@"dot_lbrace" => 163,
            .@"colon" => 67,
            .@"assign" => 69,
            .@"lparen" => 96,
            .@"comma" => 97,
            .@"rparen" => 100,
            .@"lbracket" => 106,
            .@"rbracket" => 107,
            .@"dot" => 122,
            .@"ampersand" => 145,
            .@"tilde" => 146,
            .@"star" => 151,
            .@"at" => 162,
            .@"rbrace" => 166,
            .@"lbrace" => 167,
            .@"bar" => 189,
            .@"caret" => 190,
            .@"lt" => 193,
            .@"gt" => 194,
            .@"plus" => 199,
            .@"minus" => 200,
            .@"slash" => 201,
            .@"percent" => 202,
            .@"fixed_assign" => 70,
            .@"arrow" => 101,
            .@"dotdot" => 126,
            .@"fat_arrow" => 127,
            .@"nullish" => 131,
            .@"plus_assign" => 139,
            .@"minus_assign" => 140,
            .@"star_assign" => 141,
            .@"slash_assign" => 142,
            .@"move_assign" => 143,
            .@"pipe" => 186,
            .@"or_sym" => 187,
            .@"and_sym" => 188,
            .@"eq" => 191,
            .@"ne" => 192,
            .@"le" => 195,
            .@"ge" => 196,
            .@"lshift" => 197,
